import{_ as t,a as o,b as i,c as a,d as r}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as d}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as n,o as l,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const z=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/ocr.md","filePath":"it-IT/Other/ocr.md","lastUpdated":1781962217000}'),p={name:"it-IT/Other/ocr.md"};function u(m,e,g,h,b,f){return l(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR estrae testo da immagini, scansioni e screenshot di documenti.</p><p>Dopo il riconoscimento, puoi copiare il risultato, esportarlo come <code>Markdown</code>, <code>PDF</code> o <code>Word</code>, oppure scaricare più formati insieme in un pacchetto.</p><h2 id="cosa-puo-fare-ocr" tabindex="-1">Cosa può fare OCR <a class="header-anchor" href="#cosa-puo-fare-ocr" aria-label="Permalink to &quot;Cosa può fare OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funzione</th><th>Descrizione</th></tr></thead><tbody><tr><td>Riconoscimento testo immagine</td><td>Estrae testo da immagini, screenshot e scansioni.</td></tr><tr><td>Riconoscimento layout documento</td><td>Più adatto a tabelle, formule, timbri e layout misti testo-immagine.</td></tr><tr><td>Più servizi</td><td>Supporta Baidu PaddleOCR, Microsoft Azure Vision e Google Vision.</td></tr><tr><td>Copia risultati</td><td>Copia il testo riconosciuto dopo l&#39;elaborazione.</td></tr><tr><td>Esporta file</td><td>Esporta <code>Markdown</code>, <code>PDF</code> e <code>Word</code>.</td></tr><tr><td>Pacchetto batch</td><td>Dopo più riconoscimenti, scarica i risultati come pacchetto.</td></tr></tbody></table><h2 id="configurare-prima-i-servizi-ocr" tabindex="-1">Configurare prima i servizi OCR <a class="header-anchor" href="#configurare-prima-i-servizi-ocr" aria-label="Permalink to &quot;Configurare prima i servizi OCR&quot;">​</a></h2><p>Apri:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+t+'" alt="Geolocalizzazione IP e OCR" loading="lazy"></p><p>Inserisci le credenziali dei servizi che vuoi usare:</p><table tabindex="0"><thead><tr><th>Servizio</th><th>Cosa inserire</th><th>Ideale per</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Prima scelta consigliata. Buono per documenti, immagini, tabelle e layout misti.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> e <code>Azure Vision API Key</code></td><td>Utile se usi già servizi cloud Microsoft.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. L&#39;account di servizio <code>JSON</code> serve solo per interrogare la quota.</td><td>Utile se usi Google Cloud.</td></tr></tbody></table><p>Salva dopo aver inserito le credenziali.</p><p>Per il primo test basta configurare un solo servizio. Non servono tutti e tre.</p><h2 id="configurare-google-vision" tabindex="-1">Configurare Google Vision <a class="header-anchor" href="#configurare-google-vision" aria-label="Permalink to &quot;Configurare Google Vision&quot;">​</a></h2><p>La configurazione Google ha due parti:</p><table tabindex="0"><thead><tr><th>Obiettivo</th><th>Requisito</th></tr></thead><tbody><tr><td>Usare OCR</td><td>Abilitare <code>Cloud Vision API</code>, poi creare una <code>API Key</code>.</td></tr><tr><td>Interrogare uso</td><td>Creare un service account, assegnare <code>Monitoring Viewer</code>, poi scaricare il <code>JSON</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="Google API key e service account" loading="lazy"></p><h3 id="usare-google-per-ocr" tabindex="-1">Usare Google per OCR <a class="header-anchor" href="#usare-google-per-ocr" aria-label="Permalink to &quot;Usare Google per OCR&quot;">​</a></h3><ol><li>Apri Google Cloud Console.</li><li>Vai a <code>APIs &amp; Services</code>.</li><li>Apri <code>Library</code>, cerca <code>Cloud Vision API</code> e abilitala.</li><li>Torna a <code>Credentials</code>.</li><li>Crea una <code>API Key</code>.</li><li>Apri la API Key e copiala.</li><li>Incollala in <code>Google Vision API Key</code> in ImgBed.</li><li>Salva.</li></ol><p>Poi potrai scegliere Google Vision nella finestra OCR.</p><h3 id="interrogare-l-uso-google" tabindex="-1">Interrogare l&#39;uso Google <a class="header-anchor" href="#interrogare-l-uso-google" aria-label="Permalink to &quot;Interrogare l&#39;uso Google&quot;">​</a></h3><p>La query quota non è necessaria per il riconoscimento.</p><p>Mostra solo in modo approssimativo quante chiamate Google Vision sono state usate negli ultimi 30 giorni.</p><ol><li>In Google Cloud Console apri <code>IAM &amp; Admin</code>.</li><li>Apri <code>Service Accounts</code>.</li><li>Crea un service account, per esempio <code>vision-monitor</code>.</li><li>Assegnagli il ruolo <code>Monitoring Viewer</code>.</li><li>Apri i dettagli del service account e crea una chiave.</li><li>Scegli <code>JSON</code>.</li><li>Scarica il file JSON generato.</li><li>Torna in ImgBed e importalo sotto service account <code>JSON</code> (opzionale).</li><li>Dopo l&#39;import riuscito, clicca query quota.</li></ol><p>Dopo l&#39;import, ImgBed mostra il nome del progetto a cui appartiene il service account. Durante la query, ImgBed legge i dati Google monitoring e mostra il numero di chiamate del mese.</p><p>In breve:</p><table tabindex="0"><thead><tr><th>Elemento</th><th>Scopo</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Esegue il riconoscimento OCR.</td></tr><tr><td>Service account <code>JSON</code></td><td>Interroga quante chiamate Google Vision sono state usate.</td></tr><tr><td>Ruolo <code>Monitoring Viewer</code></td><td>Permette al service account di leggere dati d&#39;uso.</td></tr></tbody></table><h2 id="ottenere-un-baidu-paddleocr-token" tabindex="-1">Ottenere un Baidu PaddleOCR Token <a class="header-anchor" href="#ottenere-un-baidu-paddleocr-token" aria-label="Permalink to &quot;Ottenere un Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR richiede un access token.</p><p><img src="'+o+'" alt="Ottieni token PaddleOCR" loading="lazy"></p><p>Apri la finestra di chiamata <code>API</code> nella pagina Baidu PaddleOCR, clicca per ottenere un token e copialo.</p><p>Torna in ImgBed, incollalo in <code>PaddleOCR Token</code> e salva.</p><h2 id="avviare-il-riconoscimento" tabindex="-1">Avviare il riconoscimento <a class="header-anchor" href="#avviare-il-riconoscimento" aria-label="Permalink to &quot;Avviare il riconoscimento&quot;">​</a></h2><p>In Gestione file, seleziona un&#39;immagine o uno screenshot di documento e clicca <code>OCR</code>.</p><p><img src="'+i+'" alt="Riconoscimento OCR" loading="lazy"></p><p>Nella finestra scegli servizio e modello.</p><p>Modelli PaddleOCR comuni:</p><table tabindex="0"><thead><tr><th>Modello</th><th>Ideale per</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Default consigliato. Buono per documenti, tabelle, formule, timbri e layout misti.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Immagini semplici, testo comune e riconoscimento leggero.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingue, immagini complesse e contenuti simili a grafici.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Pagine documento più complesse e recupero layout.</td></tr></tbody></table><p>Se non sei sicuro, parti da <code>PP-StructureV3</code>.</p><h2 id="opzioni-avanzate" tabindex="-1">Opzioni avanzate <a class="header-anchor" href="#opzioni-avanzate" aria-label="Permalink to &quot;Opzioni avanzate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Descrizione</th></tr></thead><tbody><tr><td>Correzione orientamento</td><td>Usa se l&#39;immagine è ruotata o inclinata.</td></tr><tr><td>Appiattimento documento</td><td>Usa per documenti fotografati con curvatura o prospettiva.</td></tr><tr><td>Rilevamento layout</td><td>Usa quando vuoi conservare titoli, paragrafi, tabelle e struttura immagine.</td></tr><tr><td>Riconoscimento grafici</td><td>Usa se l&#39;immagine contiene grafici o strutture complesse.</td></tr><tr><td>Migliora <code>Markdown</code></td><td>Rende il Markdown esportato più leggibile.</td></tr></tbody></table><p>Per screenshot normali, mantieni poche opzioni. Per scansioni di documenti, abilita più opzioni legate ai documenti.</p><h2 id="visualizzare-risultati" tabindex="-1">Visualizzare risultati <a class="header-anchor" href="#visualizzare-risultati" aria-label="Permalink to &quot;Visualizzare risultati&quot;">​</a></h2><p>Dopo il riconoscimento, la finestra mostra il risultato.</p><p>Puoi copiarlo direttamente o scegliere i formati di esportazione.</p><p><img src="'+a+'" alt="Riconoscimento PDF" loading="lazy"></p><p>Per pagine documento, il <code>PDF</code> esportato può mantenere l&#39;aspetto della pagina rendendo il testo ricercabile. È utile per archiviare scansioni e ritrovare contenuti in seguito.</p><h2 id="scegliere-il-formato-di-esportazione" tabindex="-1">Scegliere il formato di esportazione <a class="header-anchor" href="#scegliere-il-formato-di-esportazione" aria-label="Permalink to &quot;Scegliere il formato di esportazione&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Formato</th><th>Ideale per</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Note, documentazione e modifica successiva.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Conservare l&#39;aspetto pagina e risultati da scansione.</td></tr><tr><td><code>Word (.docx)</code></td><td>Modifica layout, testo e passaggio ad altre persone.</td></tr><tr><td>Esporta tutto</td><td>Salva più formati e immagine originale, adatto ad archivi importanti.</td></tr></tbody></table><p>Se ti serve solo il testo, esporta Markdown.</p><p>Se ti serve l&#39;aspetto pagina, usa PDF o Word.</p><h2 id="output-word" tabindex="-1">Output Word <a class="header-anchor" href="#output-word" aria-label="Permalink to &quot;Output Word&quot;">​</a></h2><p>I documenti Word esportati possono essere aperti e modificati con software office.</p><p><img src="'+r+`" alt="Risultato Word" loading="lazy"></p><p>Alcuni documenti includono immagini riconosciute, titoli e paragrafi nell&#39;output Word.</p><p>La qualità dipende da nitidezza dell&#39;originale, modello scelto e complessità del documento.</p><h2 id="tipi-di-file-migliori-per-ocr" tabindex="-1">Tipi di file migliori per OCR <a class="header-anchor" href="#tipi-di-file-migliori-per-ocr" aria-label="Permalink to &quot;Tipi di file migliori per OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tipo file</th><th>Consiglio</th></tr></thead><tbody><tr><td>Screenshot chiari</td><td>Riconosci direttamente.</td></tr><tr><td>Scansioni</td><td>Preferisci <code>PP-StructureV3</code>.</td></tr><tr><td>Documenti fotografati</td><td>Abilita correzione orientamento e appiattimento documento.</td></tr><tr><td>Tabelle, formule, timbri</td><td>Preferisci modelli strutturati.</td></tr><tr><td>Immagini con testo breve semplice</td><td><code>PP-OCRv5</code> di solito basta.</td></tr></tbody></table><p>Immagini più nitide e testo più dritto producono risultati migliori.</p><h2 id="casi-comuni" tabindex="-1">Casi comuni <a class="header-anchor" href="#casi-comuni" aria-label="Permalink to &quot;Casi comuni&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Caso</th><th>Significato</th></tr></thead><tbody><tr><td>Riconoscimento fallito</td><td>Controlla che token o chiave del servizio siano salvati.</td></tr><tr><td>Riconoscimento lento</td><td>Documenti complessi e immagini grandi richiedono più tempo.</td></tr><tr><td>Tabella incompleta</td><td>Prova un modello strutturato.</td></tr><tr><td>Testo con errori</td><td>Sfocatura, riflessi e inclinazione aumentano gli errori. Prova un&#39;immagine più chiara.</td></tr><tr><td>Word contiene molte immagini</td><td>I modelli strutturati possono conservare alcune immagini riconosciute. È normale.</td></tr></tbody></table><h3 id="la-query-quota-google-fallisce" tabindex="-1">La query quota Google fallisce <a class="header-anchor" href="#la-query-quota-google-fallisce" aria-label="Permalink to &quot;La query quota Google fallisce&quot;">​</a></h3><p>Controlla:</p><ol><li>Il service account <code>JSON</code> è stato importato.</li><li>Il service account ha il ruolo <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> è abilitata per il progetto.</li></ol><p>Se ti serve solo OCR e non la query uso, puoi ignorare il JSON del service account e compilare solo <code>Google Vision API Key</code>.</p><h2 id="flusso-rapido" tabindex="-1">Flusso rapido <a class="header-anchor" href="#flusso-rapido" aria-label="Permalink to &quot;Flusso rapido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apri System Settings</span></span>
<span class="line"><span>-&gt; Apri Other Settings</span></span>
<span class="line"><span>-&gt; Inserisci credenziali servizio OCR</span></span>
<span class="line"><span>-&gt; Salva</span></span>
<span class="line"><span>-&gt; Torna a Gestione file</span></span>
<span class="line"><span>-&gt; Seleziona un file e clicca OCR</span></span>
<span class="line"><span>-&gt; Scegli un modello</span></span>
<span class="line"><span>-&gt; Attendi il riconoscimento</span></span>
<span class="line"><span>-&gt; Copia risultati o esporta Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const O=n(p,[["render",u]]);export{z as __pageData,O as default};
